import React, {useState, useEffect} from 'react'
import { View, TextInput, Appbar, ScrollView} from 'react-native'
// import { TextInput } from 'react-native-gesture-handler'
import { firebase, db } from '../../firebase/config'
import {Button} from 'react-native-elements'



const Expenses = (props) => {
    const [expense, setExpense] = useState('')
    const [name, setName] = useState('')
    const [amount, setAmount] = useState(0)
    const [category, setCategory] = useState('')
    const [recurring, setRecurring] = useState(Boolean)

    const ref = db.collection('users')
    const userId = props.extraData.id;


     const addExp = async() => {
        await ref.doc('userId').set({
            category: category,
            name: name,
            amount: amount,
            recurring: recurring

        });
        setCategory('')
        setName('')
        setAmount(0)
        setRecurring(Boolean)  
    }


    return (

        <View>
            <TextInput label={'new expense'} value={expense} onChangeText={setCategory}/>




            <Button onPress={() => addExp()}>Add Expense</Button>
        </View>
    )
}



export default Expenses;
